impl From<u16> for Csharp {
    #[inline]
    fn from(x: u16) -> Self {
        num::FromPrimitive::from_u16(x).unwrap_or(Self::Error)
    }
}

// Csharp == u16
impl PartialEq<u16> for Csharp {
    #[inline]
    fn eq(&self, x: &u16) -> bool {
        *self == Into::<Self>::into(*x)
    }
}

// u16 == Csharp
impl PartialEq<Csharp> for u16 {
    #[inline]
    fn eq(&self, x: &Csharp) -> bool {
        *x == *self
    }
}
